from player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player("red"), Player("black")]
        self.current_player_index = 0

    def get_current_player(self):
        return self.players[self.current_player_index]

    def switch_turns(self):
        self.current_player_index = 1 - self.current_player_index

    def make_move(self, from_x, from_y, to_x, to_y):
        piece = self.board.get_piece(from_x, from_y)
        if piece and piece.color == self.get_current_player().get_color():
            self.board.move_piece(from_x, from_y, to_x, to_y)
            self.switch_turns()

