"""
This is the main module to launch the program.
"""

from game import Game

if __name__ == "__main__":
    game = Game()
    game.board.print_board()

    while not game.is_game_over():
        player = game.get_current_player()
        move_str = input(f"Player {player.get_color()}'s move (e.g., a1-b2): ").strip()
        try:
            from_x, from_y, to_x, to_y = map(int, move_str.split('-'))
            game.make_move(from_x - 1, from_y - 1, to_x - 1, to_y - 1)
            game.board.print_board()
        except ValueError:
            print("Invalid move. Please try again.")
